11	export function parseJsonEventStream<T>({
12	  stream,
13	  schema,
14	}: {
15	  stream: ReadableStream<Uint8Array>;
16	  schema: FlexibleSchema<T>;
17	}): ReadableStream<ParseResult<T>> {
18	  return stream
19	    .pipeThrough(new TextDecoderStream())
20	    .pipeThrough(new EventSourceParserStream())
21	    .pipeThrough(
22	      new TransformStream<EventSourceMessage, ParseResult<T>>({
23	        async transform({ data }, controller) {
