342	          detectMediaType({
343	            data: uint8Data,
344	            signatures: imageMediaTypeSignatures,
345	          }) ||
346	          'image/png',
347	      };
348	    }
349	  }
350	
351	  const uint8Data = convertDataContentToUint8Array(dataContent);
352	  return {
353	    type: 'file',
354	    data: uint8Data,
355	    mediaType:
