### 5. PROVIDER FACTORY PATTERN

**Provider Creation** (from `packages/fal/src/fal-provider.ts`):

```typescript
export function createFal(options: FalProviderSettings = {}): FalProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  // Headers function - called per-request for dynamic content
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Key ${loadFalApiKey({
          apiKey: options.apiKey,
        })}`,
        ...options.headers,
      },
      `ai-sdk/fal/${VERSION}`,
    );

  // Model factory functions
  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',
      baseURL,
      headers: getHeaders,      // Dynamic headers
      fetch: options.fetch,
    });

  // Return provider object with methods
  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId) => throw NoSuchModelError(...),
    speech: createSpeechModel,
    video: createVideoModel,
    transcription: createTranscriptionModel,
    embeddingModel: (modelId) => throw NoSuchModelError(...),
  };
}

export const fal = createFal();  // Default singleton instance
```

**Provider Config Type**:

```typescript
export type FalConfig = {
  provider: string;
  url: (options: { modelId: string; path: string }) => string;
  headers: () => Record<string, string | undefined>;  // Dynamic
  fetch?: FetchFunction;
  generateId?: () => string;
};
```

