### 6. HTTP REQUEST & ERROR HANDLING

**Core postJsonToApi Pattern**:

```typescript
// From post-to-api.ts
const { responseHeaders, value: response } = await postJsonToApi({
  url: `${this.config.baseURL}/${this.modelId}`,
  headers: combineHeaders(
    await resolve(this.config.headers),
    options.headers,
  ),
  body: requestBody,
  failedResponseHandler: falFailedResponseHandler,
  successfulResponseHandler: createJsonResponseHandler(
    falImageResponseSchema,
  ),
  abortSignal: options.abortSignal,
  fetch: this.config.fetch,
});
```

**Error Response Handler** (from `packages/fal/src/fal-error.ts`):

```typescript
import { createJsonErrorResponseHandler } from '@ai-sdk/provider-utils';

export const falErrorDataSchema = z.object({
  error: z.object({
    message: z.string(),
    code: z.number(),
  }),
});

export const falFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: falErrorDataSchema,
  errorToMessage: data => data.error.message,
});
```

**Response Handler Signature**:

```typescript
type ResponseHandler<RETURN_TYPE> = (options: {
  url: string;
  requestBodyValues: unknown;
  response: Response;
}) => PromiseLike<{
  value: RETURN_TYPE;
  rawValue?: unknown;
  responseHeaders?: Record<string, string>;
}>;
```

