**Test Server Setup** (image model test example):

```typescript
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';

describe('FalImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/fal-ai/qwen-image': {
      response: {
        type: 'json-value',
        body: {
          images: [
            {
              url: 'https://api.example.com/image.png',
              width: 1024,
              height: 1024,
              content_type: 'image/png',
            },
          ],
        },
      },
    },
    'https://api.example.com/image.png': {
      response: {
        type: 'binary',
        body: Buffer.from('test-binary-content'),
      },
    },
  });

  it('should pass correct parameters', async () => {
    const model = new FalImageModel('fal-ai/qwen-image', {
      provider: 'fal.image',
      baseURL: 'https://api.example.com',
      headers: { 'api-key': 'test-key' },
      fetch,
    });

    await model.doGenerate({
      prompt: 'A test prompt',
      files: undefined,
      mask: undefined,
      n: 1,
      size: '1024x1024',
      aspectRatio: undefined,
      seed: 123,
      providerOptions: {},
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      prompt: 'A test prompt',
      seed: 123,
      image_size: { width: 1024, height: 1024 },
      num_images: 1,
    });

    expect(server.calls[0].requestHeaders).toStrictEqual({
      'content-type': 'application/json',
      'api-key': 'test-key',
    });
  });
});
