import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.pixelart.ai/v1';
const TEST_MODEL_ID = 'pixelart-v1';
const TEST_PROMPT = 'A pixelated sunset over a retro cityscape';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel(TEST_MODEL_ID, {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: { currentDate },
  });
}

const TEST_B64 = 'aGVsbG8='; // base64 for "hello"

const DEFAULT_RESPONSE = {
  images: [{ b64_json: TEST_B64 }],
};

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [`${TEST_BASE_URL}/images/generate`]: {
      response: {
        type: 'json-value',
        body: DEFAULT_RESPONSE,
      },
    },
  });

  describe('doGenerate', () => {
    it('should pass prompt, n, seed, and size in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt: TEST_PROMPT,
        n: 2,
        seed: 42,
        size: { width: 512, height: 512 },
      });
    });

    it('should omit size from request body when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('size');
    });

    it('should pass style from providerOptions.pixelart', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: '8bit' } },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ style: '8bit' });
    });

    it('should pass pixelDensity as pixel_density in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { pixelDensity: 64 } },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ pixel_density: 64 });
    });

    it('should pass both style and pixelDensity together', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: 7,
        providerOptions: { pixelart: { style: 'retro', pixelDensity: 32 } },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt: TEST_PROMPT,
        n: 1,
        seed: 7,
        size: { width: 1024, height: 1024 },
        style: 'retro',
        pixel_density: 32,
      });
    });

    it('should emit an unsupported warning when aspectRatio is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'The PixelArt provider does not support aspectRatio. Use size instead.',
      });
    });

    it('should return images as base64 strings from the response', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toStrictEqual([TEST_B64]);
    });

    it('should return the correct response metadata', async () => {
      const fixedDate = new Date('2026-04-06T00:00:00Z');
      const model = createBasicModel({ currentDate: () => fixedDate });

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.modelId).toBe(TEST_MODEL_ID);
      expect(result.response.timestamp).toStrictEqual(fixedDate);
    });

    it('should include providerMetadata with pixelart images', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.providerMetadata).toMatchObject({
        pixelart: {
          images: [{ b64_json: TEST_B64 }],
        },
      });
    });

    it('should set Authorization header from config', async () => {
      const model = createBasicModel({
        headers: { Authorization: 'Bearer my-secret-key' },
      });

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestHeaders['authorization']).toBe(
        'Bearer my-secret-key',
      );
    });

    it('should have maxImagesPerCall of 4', () => {
      const model = createBasicModel();
      expect(model.maxImagesPerCall).toBe(4);
    });

    it('should have specificationVersion of v3', () => {
      const model = createBasicModel();
      expect(model.specificationVersion).toBe('v3');
    });

    it('should have provider name of pixelart.image', () => {
      const model = createBasicModel();
      expect(model.provider).toBe('pixelart.image');
    });
  });
});

